import{_ as a,o as i,c as t,a3 as n}from"./chunks/framework.CjquFG0V.js";const g=JSON.parse('{"title":"85. Classifications Definitions And Wages","description":"","frontmatter":{"title":"85. Classifications Definitions And Wages","eba":"Allied Health Professionals 2021-2026","topics":["wages","employment","preliminary"]},"headers":[],"relativePath":"ebas/allied-health/classification-staffing/85-classifications-definitions-and-wages.md","filePath":"ebas/allied-health/classification-staffing/85-classifications-definitions-and-wages.md"}'),s={name:"ebas/allied-health/classification-staffing/85-classifications-definitions-and-wages.md"};function r(o,e,l,d,p,c){return i(),t("div",null,[...e[0]||(e[0]=[n('<h1 id="_85-classifications-definitions-and-wages" tabindex="-1">85. Classifications Definitions And Wages <a class="header-anchor" href="#_85-classifications-definitions-and-wages" aria-label="Permalink to &quot;85. Classifications Definitions And Wages&quot;">​</a></h1><p><strong>85.1</strong> The classification descriptors are set out in <a href="/eba/ebas/allied-health/appendices/4-classification-definitions.html">Appendix 4</a> (Classification Definitions), including specific provisions relating to Advanced Practice.</p><p><strong>85.2</strong> The weekly full-time wage rates applicable to each classification during the period that this Agreement operates are set out in <a href="/eba/ebas/allied-health/appendices/2-wage-rates.html">Appendix 2</a> (Wage Rates).</p><p><strong>85.3</strong> Appointment to a wage point will be based on the Employee’s Experience as defined at subclause 85.12(a) below.</p><p>Example 1: A Physiotherapist with two (2) completed years’ Experience at AHP1 Grade 2 is classified as an AHP1 Grade 2, Year 3. They terminate their employment and commence with a new Employer as a Physiotherapist Grade 2. The Physiotherapist’s previous AHP1 Grade 2 experience means they commence the new employment at AHP1 Grade 2 Year 3. Example 2: A Grade 3 Nuclear Medicine Technologist (NMT) has 10 years’ Experience at Grade 3 and is classified as an AHP1 Grade 3, Year 4. The Grade 3 position is made redundant and the NMT agrees to be redeployed to a Grade 2 position. Due to the NMT’s Grade 3 experience, the NMT will be employed as an AHP1 Grade 2, Year 4 after redeployment. Nine (9) months after the redeployment, the NMT is appointed to a Grade 3 position. The NMT’s previous Grade 3 experience means they are employed as a AHP1 Grade 3, Year 4. Example 3: A Medical Imaging Technologist (MIT) is classified as a Level 7 MIT for six (6) years under a private Radiography enterprise agreement. This Level 7 MIT classification is the equivalent of AHP1 Grade 4 in this Agreement. This MIT is then employed by an Employer covered by this Agreement as a Grade 4 MIT. The Employee’s previous experience at a level equivalent to AHP1 Grade 4 under this Agreement means they commence the new employment at AHP1 Grade 4 Year 4.</p><p><strong>85.4</strong> Progression through all classifications for which there is more than one wage point will be by annual increments, having regard to the acquisition and utilisation of skills and knowledge through experience in the Employee’s practice setting(s) over such period.</p><p><strong>85.5</strong> Advancement by an Employee through the Experience increments within AHP1 grades in the classification structure will occur upon the completion by the Employee of each 12 month period calculated from the Employee’s commencement in a grade within the AHP1 classifications, irrespective of whether a 12 month period (or any part) was served as a full-time or part-time Employee, provided that:</p><p><strong>(a)</strong> an Employee who holds or is qualified to hold a relevant Masters Degree will commence at the AHP1, Grade 1, Year 2 rate; and</p><p><strong>(b)</strong> an Employee who holds or is qualified to hold a relevant Doctoral Degree will commence at the AHP1, Grade 1, Year 4 rate.</p><p><strong>85.6</strong> Classifying Allied Health Managers and Assistant Allied Health Managers When classifying an Employee as an Allied Health Manager or Assistant Allied Health Manager, the number of Full Time Employees (as defined in section B of increment:</p><p><strong>(a)</strong> in the case of a Grade 3 Allied Health Manager or Assistant Allied Health Manager, see <a href="/eba/ebas/allied-health/appendices/4-classification-definitions.html">Appendix 4</a> – Section B, subclause 5.4; and</p><p><strong>(b)</strong> in the case of a Grade 4 Allied Health Manager or Assistant Allied Health Manager, see <a href="/eba/ebas/allied-health/appendices/4-classification-definitions.html">Appendix 4</a> – Section B, subclause 6.4.</p><p><strong>85.7</strong> Entry Level – New Graduate – Rural, Regional and Community Health Centres/Services</p><p><strong>(a)</strong> This subclause 85.7 applies to Employees employed in a Rural or Regional Health Service or in a Community Health Centre/Service.</p><p><strong>(b)</strong> An Employee who holds:</p><p><strong>(i)</strong> a relevant four year undergraduate qualification; or</p><p><strong>(ii)</strong> a relevant three year undergraduate qualification and either holds an Honours degree, or is required to do a 12 month internship; will commence at the AHP1, Grade 1, Year 2 rate.</p><p><strong>85.8</strong> Overlapping Pay Points Between Grades An Employee who moves to or is appointed to a higher grade/level/class will be paid at the rate within that grade/level/class immediately above their previous rate of pay.</p><p><strong>85.9</strong> Grade 3 Allied Health Manager The AHP1 Grade 3, Year 3B and 4B rates in <a href="/eba/ebas/allied-health/appendices/2-wage-rates.html">Appendix 2</a> will apply to Grade 3 Allied Health Managers (as defined in <a href="/eba/ebas/allied-health/appendices/4-classification-definitions.html">Appendix 4</a>) in lieu of the AHP1 Grade 3, Year 3 and 4 rates that apply to all other Grade 3 Employees.</p><p><strong>85.10</strong> Interns (Medical Imaging Technologist (Radiographer), Nuclear Medicine Technologist and Radiation Therapy Technologist) – Entry Level Intern Medical Imaging Technologist (Radiographer), Nuclear Medicine Technologist and Radiation Therapy Technologist (Radiation Therapist) Employees who hold or are qualified to hold a:</p><p><strong>(a)</strong> three year undergraduate qualification will be classified at AHP1 Intern – 3 year degree;</p><p><strong>(b)</strong> four year undergraduate qualification will be classified at AHP1 Intern – 4 year degree; and</p><p><strong>(c)</strong> Masters Degree will be classified at AHP1 Intern – Masters degree.</p><p><strong>85.11</strong> Changes to Classification Structure</p><p><strong>(a)</strong> Upon the Agreement commencing operation:</p><p><strong>(i)</strong> the number of Years (increments) in AHP1 Grade 1 will be reduced from seven (7) to five (5); and</p><p><strong>(ii)</strong> Dental Prosthetist will cease being an AHP2 classification and become an AHP1 classification.</p><p><strong>(b)</strong> Translation arrangements for the changes in subclause 85.11(a) are in Appendix 2 Part B and Part C of this Agreement.</p><p><strong>85.12</strong> Definitions In this clause 85:</p><p><strong>(a)</strong> Experience means experience in the Employee’s profession at an equivalent or higher classification obtained within the last five (5) years at any workplace, excluding any unpaid leave provisions in the Agreement (or any previous applicable instrument).</p><p><strong>(b)</strong> a three year undergraduate qualification or four year undergraduate qualification means a qualification assessed as a Bachelor Degree (or equivalent) under the Australian Qualifications Framework level 7 criteria;</p><p><strong>(c)</strong> a Bachelor Honours Degree means a qualification assessed as a Bachelor Honours Degree (or equivalent) under the Australian Qualifications Framework level 8 criteria;</p><p><strong>(d)</strong> a Masters Degree means a qualification assessed as a Masters Degree (or equivalent) under the Australian Qualifications Framework level 9 criteria; and</p><p><strong>(e)</strong> a Doctoral Degree means a qualification assessed as a Doctoral Degree (or equivalent) under the Australian Qualifications Framework level 10 criteria.</p><p>Plain language terms: glossary, meanings.</p>',35)])])}const m=a(s,[["render",r]]);export{g as __pageData,m as default};
